// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('Check button add - field 部署名 -  enter max value 100 character (enter 101 character or more)', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('Check button add - field 部署名 -  enter max value 100 character (enter 101 character or more)', async function() {
    await driver.get("http://localhost:4200/admin-user/add-department");
    await driver.manage().window().setRect({ width: 1936, height: 1056 });
    await driver.findElement(By.css(".ant-layout-content")).click();
    await driver.findElement(By.id("department_name")).click();
    await driver.executeScript("window.scrollTo(0,0)");
    await driver.findElement(By.id("department_name")).sendKeys("aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa");
    await driver.findElement(By.css(".ant-form")).click();
    await driver.findElement(By.css(".ant-btn-default")).click();
    await driver.findElement(By.css("#department_name_help > .ant-form-item-explain-error")).click();
    assert(await driver.findElement(By.css("#department_name_help > .ant-form-item-explain-error")).getText() == "100文字以内で入力してください。");
  });
});
